// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb.hypergraph;

import java.util.LinkedHashSet;
import java.util.Set;

/**
 * Test oracle: brute-force "DPsub" enumeration of all csg-cmp pairs. Iterates every node set in ascending numeric order
 * (so subsets come before supersets), marks a set connected when it splits into two connected halves crossing an edge,
 * and records each such split once in canonical form (the left half contains the lowest-index node of the union — the
 * same convention DPhyp's seed order produces). Exponential and only suitable for small test graphs.
 */
final class NaiveEnumerator {

	record Pair(long left, long right) {
		@Override
		public String toString() {
			return NodeSets.describe(left) + "|" + NodeSets.describe(right);
		}
	}

	private NaiveEnumerator() {
	}

	static Set<Pair> allPairs(Hypergraph graph) {
		int nodeCount = graph.nodeCount();
		if (nodeCount > 20) {
			throw new IllegalArgumentException("oracle is exponential; keep test graphs small");
		}
		Set<Pair> pairs = new LinkedHashSet<>();
		boolean[] connected = new boolean[1 << nodeCount];
		for (long set = 1; set < (1L << nodeCount); set++) {
			if (Long.bitCount(set) == 1) {
				connected[(int) set] = true;
				continue;
			}
			long lowest = NodeSets.lowestBit(set);
			for (long left = NodeSets.nextSubsetOf(0, set); left != 0; left = NodeSets.nextSubsetOf(left, set)) {
				if (left == set || (left & lowest) == 0) {
					continue;
				}
				long right = set & ~left;
				if (connected[(int) left] && connected[(int) right] && connectsDirectly(graph, left, right)) {
					pairs.add(new Pair(left, right));
					connected[(int) set] = true;
				}
			}
		}
		return pairs;
	}

	/** Independent re-implementation of "some hyperedge crosses this cut" so oracle and implementation can disagree. */
	private static boolean connectsDirectly(Hypergraph graph, long a, long b) {
		for (int e = 0; e < graph.edgeCount(); e++) {
			long left = graph.edgeLeft(e);
			long right = graph.edgeRight(e);
			boolean leftInA = (left & ~a) == 0;
			boolean leftInB = (left & ~b) == 0;
			boolean rightInA = (right & ~a) == 0;
			boolean rightInB = (right & ~b) == 0;
			if ((leftInA && rightInB) || (leftInB && rightInA)) {
				return true;
			}
		}
		return false;
	}
}
